package com.example.sociallogin

object SecretsProvider {

    val facebookAppId: String
        get() = BuildConfig.FACEBOOK_APP_ID.also {
            require(it.isNotBlank()) { "FACEBOOK_APP_ID not configured. Set it in secrets.properties or environment variables." }
        }

    val googleOAuthClientId: String
        get() = BuildConfig.GOOGLE_OAUTH_CLIENT_ID.also {
            require(it.isNotBlank()) { "GOOGLE_OAUTH_CLIENT_ID not configured. Set it in secrets.properties or environment variables." }
        }

    // Note: Client secrets should NEVER be in the mobile app.
    // OAuth secrets belong on your backend server only.
    // Mobile apps use PKCE flow which doesn't require a client secret.
}

