package com.example.sociallogin

import android.content.Intent
import android.os.Bundle
import androidx.activity.ComponentActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.GraphRequest
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult

class FacebookLoginHandler(
    private val activity: ComponentActivity,
    private val callback: SocialLoginCallback
) {
    private val callbackManager = CallbackManager.Factory.create()

    init {
        LoginManager.getInstance().registerCallback(
            callbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    fetchFacebookUserProfile(result)
                }

                override fun onCancel() {
                    callback.onLoginResult(SocialLoginResult.Cancelled(SocialProvider.FACEBOOK))
                }

                override fun onError(error: FacebookException) {
                    callback.onLoginResult(
                        SocialLoginResult.Error(
                            provider = SocialProvider.FACEBOOK,
                            message = error.message ?: "Facebook login failed",
                            exception = error
                        )
                    )
                }
            }
        )
    }

    fun login() {
        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            callbackManager,
            listOf("email", "public_profile")
        )
    }

    fun logout() {
        LoginManager.getInstance().logOut()
    }

    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }

    private fun fetchFacebookUserProfile(loginResult: LoginResult) {
        val request = GraphRequest.newMeRequest(loginResult.accessToken) { jsonObject, _ ->
            try {
                val userId = jsonObject?.optString("id") ?: ""
                val name = jsonObject?.optString("name")
                val email = jsonObject?.optString("email")
                val pictureUrl = jsonObject
                    ?.optJSONObject("picture")
                    ?.optJSONObject("data")
                    ?.optString("url")

                callback.onLoginResult(
                    SocialLoginResult.Success(
                        provider = SocialProvider.FACEBOOK,
                        userId = userId,
                        displayName = name,
                        email = email,
                        accessToken = loginResult.accessToken.token,
                        profilePictureUrl = pictureUrl
                    )
                )
            } catch (e: Exception) {
                callback.onLoginResult(
                    SocialLoginResult.Error(
                        provider = SocialProvider.FACEBOOK,
                        message = "Failed to parse Facebook profile",
                        exception = e
                    )
                )
            }
        }

        val parameters = Bundle().apply {
            putString("fields", "id,name,email,picture.type(large)")
        }
        request.parameters = parameters
        request.executeAsync()
    }
}

