// =========================================================================
package com.example.sociallogin

import android.content.Intent
import androidx.activity.ComponentActivity
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import androidx.activity.result.contract.ActivityResultContracts
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient
import com.google.android.gms.common.api.ApiException

class GoogleLoginHandler(
    private val activity: ComponentActivity,
    private val callback: SocialLoginCallback
) {
    private val oneTapClient: SignInClient = Identity.getSignInClient(activity)
    private val signInRequest: BeginSignInRequest
    private val signUpRequest: BeginSignInRequest
    private val signInLauncher: ActivityResultLauncher<IntentSenderRequest>

    init {
        val clientId = SecretsProvider.googleOAuthClientId

        signInRequest = BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(clientId)
                    .setFilterByAuthorizedAccounts(true)
                    .build()
            )
            .setAutoSelectEnabled(true)
            .build()

        signUpRequest = BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(clientId)
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .build()

        signInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            handleSignInResult(result.resultCode, result.data)
        }
    }

    fun login() {
        oneTapClient.beginSignIn(signInRequest)
            .addOnSuccessListener(activity) { signInResult ->
                val intentSenderRequest = IntentSenderRequest.Builder(
                    signInResult.pendingIntent.intentSender
                ).build()
                signInLauncher.launch(intentSenderRequest)
            }
            .addOnFailureListener(activity) {
                // No previously authorized accounts; try sign-up flow
                oneTapClient.beginSignIn(signUpRequest)
                    .addOnSuccessListener(activity) { signUpResult ->
                        val intentSenderRequest = IntentSenderRequest.Builder(
                            signUpResult.pendingIntent.intentSender
                        ).build()
                        signInLauncher.launch(intentSenderRequest)
                    }
                    .addOnFailureListener(activity) { e ->
                        callback.onLoginResult(
                            SocialLoginResult.Error(
                                provider = SocialProvider.GOOGLE,
                                message = e.message ?: "Google sign-in not available",
                                exception = e as? Exception
                            )
                        )
                    }
            }
    }

    fun logout() {
        oneTapClient.signOut()
    }

    private fun handleSignInResult(resultCode: Int, data: Intent?) {
        try {
            val credential = oneTapClient.getSignInCredentialFromIntent(data)
            val idToken = credential.googleIdToken
            val userId = credential.id
            val displayName = credential.displayName
            val profilePictureUri = credential.profilePictureUri

            if (idToken != null) {
                callback.onLoginResult(
                    SocialLoginResult.Success(
                        provider = SocialProvider.GOOGLE,
                        userId = userId,
                        displayName = displayName,
                        email = userId, // Google ID is typically the email
                        accessToken = idToken,
                        profilePictureUrl = profilePictureUri?.toString()
                    )
                )
            } else {
                callback.onLoginResult(
                    SocialLoginResult.Error(
                        provider = SocialProvider.GOOGLE,
                        message = "No ID token received from Google"
                    )
                )
            }
        } catch (e: ApiException) {
            callback.onLoginResult(
                SocialLoginResult.Error(
                    provider = SocialProvider.GOOGLE,
                    message = "Google sign-in failed: ${e.statusCode}",
                    exception = e
                )
            )
        }
    }
}

