// =========================================================================
package com.example.sociallogin

import android.content.Intent
import androidx.activity.ComponentActivity

class SocialLoginManager(
    private val activity: ComponentActivity,
    private val callback: SocialLoginCallback
) {
    private val facebookHandler: FacebookLoginHandler by lazy {
        FacebookLoginHandler(activity, callback)
    }

    private val googleHandler: GoogleLoginHandler by lazy {
        GoogleLoginHandler(activity, callback)
    }

    fun loginWithFacebook() {
        facebookHandler.login()
    }

    fun loginWithGoogle() {
        googleHandler.login()
    }

    fun logout(provider: SocialProvider) {
        when (provider) {
            SocialProvider.FACEBOOK -> facebookHandler.logout()
            SocialProvider.GOOGLE -> googleHandler.logout()
        }
    }

    fun logoutAll() {
        facebookHandler.logout()
        googleHandler.logout()
    }

    // Required for Facebook SDK on older activity result APIs
    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookHandler.onActivityResult(requestCode, resultCode, data)
    }
}

