package com.example.sociallogin

import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.TextView
import android.widget.Toast
import androidx.activity.ComponentActivity

class LoginActivity : ComponentActivity(), SocialLoginCallback {

    private lateinit var socialLoginManager: SocialLoginManager
    private lateinit var statusText: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        socialLoginManager = SocialLoginManager(this, this)

        statusText = findViewById(R.id.statusText)

        findViewById<Button>(R.id.btnFacebookLogin).setOnClickListener {
            socialLoginManager.loginWithFacebook()
        }

        findViewById<Button>(R.id.btnGoogleLogin).setOnClickListener {
            socialLoginManager.loginWithGoogle()
        }

        findViewById<Button>(R.id.btnLogout).setOnClickListener {
            socialLoginManager.logoutAll()
            statusText.text = "Logged out"
        }
    }

    override fun onLoginResult(result: SocialLoginResult) {
        when (result) {
            is SocialLoginResult.Success -> {
                val message = "Logged in via ${result.provider}\n" +
                        "Name: ${result.displayName}\n" +
                        "Email: ${result.email}"
                statusText.text = message
                Log.d("SocialLogin", "Success: userId=${result.userId}")

                // Send the access token to your backend server for verification.
                // NEVER trust the token on the client side alone.
                // sendTokenToBackend(result.provider, result.accessToken)
            }

            is SocialLoginResult.Error -> {
                statusText.text = "Error: ${result.message}"
                Toast.makeText(this, "Login failed: ${result.message}", Toast.LENGTH_LONG).show()
                Log.e("SocialLogin", "Error", result.exception)
            }

            is SocialLoginResult.Cancelled -> {
                statusText.text = "Login cancelled"
                Log.d("SocialLogin", "Cancelled: ${result.provider}")
            }
        }
    }
}